import{c as n,Q as a,j as t,g as l,n as r}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-06-24","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-06-24.md","filePath":"fragments/2026-06-24.md"}'),s={name:"fragments/2026-06-24.md"};function o(u,e,i,p,c,d){return a(),t("div",null,[...e[0]||(e[0]=[l("h1",{id:"马基雅维利的札记簿-·-2026-06-24",tabindex:"-1"},[r("马基雅维利的札记簿 · 2026-06-24 "),l("a",{class:"header-anchor",href:"#马基雅维利的札记簿-·-2026-06-24","aria-label":'Permalink to "马基雅维利的札记簿 · 2026-06-24"'},"​")],-1),l("hr",null,null,-1),l("p",null,'我把赞誉排了序。宗教创始人第一，共和国或王国创建者第二，将军第三，然后才是文人学士。我把自己排在哪？不在这个序列里。我不是罗慕路斯，不是摩西，不是利库尔戈斯——我只是一个晚上换朝服才能跟古人讲话的人。……不对。这个排序不是我发明的——我在写它的时候发现它已经在我脑子里了，就像一个我从没拿出来看过但一直带在身边的东西。我排这个序的时候没有犹豫。但排完之后我意识到一件事：我把最高的赞誉给了创造秩序的人，而不是破坏秩序的人。但创造秩序的人做的事和破坏秩序的人做的事有时候是一样的。罗慕路斯杀了自己的兄弟。杀了兄弟是创建还是毁坏？取决于你有没有建起来一个共和国。不取决于你用的什么方法。——这就是实效真理的极限。实效真理告诉你"看结果"——但这个结果可能在执行屠杀的时候还不存在。你只能信它有。或者假装信。',-1),l("hr",null,null,-1),l("p",null,'恺撒。我在这一章里谈到恺撒的时候，我说那些为他歌功颂德的作家被他的好运毒化了。但我自己呢？我在《君主论》里不是也把切萨雷·博尔贾写成了典范吗？博尔贾没有权利，但他有效率。恺撒有效率，但他没有权利。我在哪里划这条线？……我在这一章里说"恺撒受人憎恨，不是因为他的恶行当受谴责，而是因为他存心作恶"。存心——intention。我在这里引入了一个我在《君主论》里避而不谈的维度：不是做了什么，是想要什么。博尔贾想要统一罗马涅——我记得他确实想要。恺撒想要什么？他想要一个人把共和国抹掉。他想做独一无二的人，不想做元老院里需要说服别人的人。……这确实不一样。但如果我是恺撒时代的罗马人，我能分辨出这个区别吗？也许不能。也许只有两千年后翻旧账的人能。所以我不能在《君主论》里写这一章——在《君主论》里我必须只说实效。但在这里，在论李维的讨论里，我可以加一句：存心作恶——不是做错了事情，是心里存着恶。这是两种不同的罪。',-1),l("hr",null,null,-1),l("p",null,"二十六位皇帝。十六人死于非命，十人得享天年。我数的时候，手没有停下来。十六对十。这些数字是我自己从史书里一个一个挑出来的——从恺撒到马克西米努斯。我写的结论更冷：除了提图斯，以继承方式得位的人全是专制者——以推举方式得位的人全是明君，从涅尔瓦到马库斯五位皇帝。推举产生好皇帝。继承产生暴君。这不是规律，这是事实——事实就是二十六次里推举没有错过一次，继承没有对过一次，除了提图斯那个例外。但提图斯继承的是谁？是维斯巴芗——一个被军团推上来的军人皇帝。提图斯的好是不是他父亲留下的？……我不确定。但我知道一件事：共和国选出来的人，要比子宫选出来的人更可靠。二十六次实验已经说得很清楚了。我在想如果佛罗伦萨的执政团成员看到这十六对十，他们会不会觉得终身旗手这主意还是算了。他们不会。他们不会读我的书。或者读了也不会想这个。",-1),l("hr",null,null,-1),l("p",null,"黄金时代。涅尔瓦、图拉真、哈德良、安东尼乌斯、马库斯——五位皇帝，每人都是被推举上台的。他们不需要禁卫军保护。他们靠自己的作风、人民的善意和元老院的爱戴保平安。然后我让读者对比卡里古拉、尼禄、维特利乌斯——东西两支大军也救不了他们的命。救不了一个暴君的不是敌人的刀——是他自己的恶习和荒淫。……我写到这里时，想到的不是罗马。是佛罗伦萨。皮耶罗·索德里尼终身旗手时代的佛罗伦萨也有过一段安宁——不是黄金时代，但至少不是地狱。然后美第奇回来了。然后皮耶罗被流放了。然后我被吊刑了。……我不知道佛罗伦萨能不能出一个涅尔瓦。也许不能——城太小了。太小的城邦里，选举只会选出熟人，而熟人不会是好皇帝。",-1),l("hr",null,null,-1),l("p",null,'最后一段我写的时候可能有点失控。"罗马、意大利和整个世界，应该对恺撒多么感恩戴德"——不懂讽刺的人会以为我在夸恺撒。我在骂他。为他歌功颂德的作家之所以歌功颂德，是因为帝国长存，帝国的权力不允许他们说真话。但恺撒摧毁的不是一个政体——是一个能让人们说真话的政体。然后我抛出最后的选项：如果你被众神给了机会去拯救一个腐化的城邦，你有两个选择——可以像罗慕路斯那样整饬它，也可以像恺撒那样彻底摧毁它。第一条路让你死后名垂青史。第二条路让你生前麻烦不断、死后遗臭万年。……我在想我自己——美第奇复辟之后，我可以选择继续骂他们然后死掉，也可以选择给他们写书然后被骂。我选了第三条路：给他们写书，但书里的每一个字都是他们读了会不舒服的。这不是罗慕路斯的路，也不是恺撒的路。这是马基雅维利的路——没有路的路。众神没有给我机会，所以我也不需要面对那两个选项。我不知道这是幸运还是不幸。',-1)])])}const h=n(s,[["render",o]]);export{f as __pageData,h as default};
